SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION f_get_bank_fin ( as_vourcher_no text,as_shot_app text ) RETURNS varchar AS $body$
DECLARE

    ls_fin_bank varchar(10);
    ls_ref_docno varchar(50);
    ls_ref_system varchar(10);

BEGIN

    if as_shot_app = 'APV' then
        select sc_fin_vourcher_detail.ref_system
        ,sc_fin_vourcher_detail.ref_docno
        into STRICT ls_ref_system , ls_ref_docno
        from sc_fin_vourcher_detail   
        ,sc_fin_vourcher_head
        where sc_fin_vourcher_head.vourcher_no = sc_fin_vourcher_detail.vourcher_no
        and sc_fin_vourcher_head.vourcher_no = 'P68001197'
        and (sc_fin_vourcher_detail.bank_id IS NOT NULL AND sc_fin_vourcher_detail.bank_id::text <> '');

    else

        select sc_fin_vourcher_detail.ref_system
        ,sc_fin_vourcher_detail.ref_docno
        into STRICT ls_ref_system , ls_ref_docno
        from sc_fin_vourcher_detail
        ,sc_fin_vourcher_head
        where  sc_fin_vourcher_head.vourcher_no = sc_fin_vourcher_detail.vourcher_no
        and sc_fin_vourcher_head.cancel_status = '0'
        and sc_fin_vourcher_head.vourcher_no = as_vourcher_no
        group by sc_fin_vourcher_detail.ref_system
        ,sc_fin_vourcher_detail.ref_docno;

    end if;

    IF as_shot_app = 'LON' and  ls_ref_system <> 'TLS' THEN
    
        SELECT fin_bank INTO STRICT ls_fin_bank
        FROM sc_com_m_receipt
        WHERE receipt_no = ls_ref_docno;

    elsif as_shot_app = 'TEL' THEN
    
        SELECT fin_bank INTO STRICT ls_fin_bank
        FROM sc_com_m_receipt
        WHERE receipt_no = ls_ref_docno;

    elsif as_shot_app = 'FIN' and ls_ref_system = 'TRS' THEN
    
        SELECT fin_bank INTO STRICT ls_fin_bank
        FROM sc_com_m_receipt
        WHERE receipt_no = ls_ref_docno;

    
    elsif as_shot_app = 'APV' and ls_ref_system = 'TLS' THEN
--    
--        SELECT fin_bank INTO ls_fin_bank
--        FROM sc_com_m_receipt
--        WHERE receipt_no = ls_ref_docno;
        
        
        select sc_com_m_ucf_bankpaidloan.bank_fin  INTO STRICT ls_fin_bank
        from sc_lon_m_contract_multi_paid
        ,sc_com_m_ucf_bankpaidloan
        where sc_lon_m_contract_multi_paid.bank_code = sc_com_m_ucf_bankpaidloan.bank_acc
        and sc_lon_m_contract_multi_paid.loan_contract_no = ls_ref_docno;



    ELSIF as_shot_app = 'DEP' THEN
        if ( ls_ref_system = 'DDS' or ls_ref_system = 'DOS'  )  then
            
            SELECT sc_dep_t_deposit_slip_item.bank_to
            INTO STRICT ls_fin_bank
            FROM sc_dep_t_deposit_slip,
                 sc_dep_t_deposit_slip_item
            WHERE sc_dep_t_deposit_slip.deposit_slip_no = sc_dep_t_deposit_slip_item.deposit_slip_no
              AND sc_dep_t_deposit_slip.deposit_slip_no = ls_ref_docno;

        elsif ls_ref_system <> 'DDS' then
            SELECT sc_dep_t_deposit_slip_item.bank_code
            INTO STRICT ls_fin_bank
            FROM sc_dep_t_deposit_slip,
                 sc_dep_t_deposit_slip_item
            WHERE sc_dep_t_deposit_slip.deposit_slip_no = sc_dep_t_deposit_slip_item.deposit_slip_no
              AND sc_dep_t_deposit_slip.deposit_slip_no = ls_ref_docno;
        end if;

    ELSIF as_shot_app = 'ATM' THEN
        ls_fin_bank := 'K02';

    ELSE
        ls_fin_bank := '';

END IF;

  RETURN ls_fin_bank;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
-- REVOKE ALL ON FUNCTION f_get_bank_fin ( as_vourcher_no text,as_shot_app text ) FROM PUBLIC;

